This follows the exact pattern of `onModelsReceived` (lines 266-273): only pass the callback when the cache is empty, so SDK commands are fetched once and cached for the runtime's lifetime.

**Step 3: Replace getCommands()** â€” replace the entire `getCommands()` method (lines 412-425) with merge logic plus a `getOrCreateRegistry()` helper:

```typescript
  /** Return the command registry, merging SDK-discovered commands with filesystem metadata. */
  async getCommands(forceRefresh?: boolean, cwd?: string): Promise<CommandRegistry> {
    const root = cwd || this.cwd;

    // forceRefresh invalidates SDK cache so next sendMessage re-fetches
    if (forceRefresh) {
      this.cachedSdkCommands = null;
    }

    // If SDK commands are cached, use them as primary source with filesystem enrichment
    if (this.cachedSdkCommands) {
      const sdkEntries: CommandEntry[] = this.cachedSdkCommands.map((c) => ({
        fullCommand: c.name.startsWith('/') ? c.name : `/${c.name}`,
        description: c.description,
        argumentHint: c.argumentHint || undefined,
      }));

      // Enrich with filesystem metadata (allowedTools, filePath, namespace, command)
      const registry = this.getOrCreateRegistry(root);
      const fsCommands = await registry.getCommands(forceRefresh);
      const fsLookup = new Map(fsCommands.commands.map((c) => [c.fullCommand, c]));

      const merged = sdkEntries.map((entry) => {
        const fsMatch = fsLookup.get(entry.fullCommand);
        if (fsMatch) {
          return {
            ...entry,
            namespace: fsMatch.namespace,
            command: fsMatch.command,
            allowedTools: fsMatch.allowedTools,
            filePath: fsMatch.filePath,
          };
        }
        return entry;
      });

      merged.sort((a, b) => a.fullCommand.localeCompare(b.fullCommand));

      return {
        commands: merged,
        lastScanned: new Date().toISOString(),
      };
    }

    // Fallback: no SDK data yet, use filesystem scanner only
    const registry = this.getOrCreateRegistry(root);
    return registry.getCommands(forceRefresh);
  }

  /** Get or create a CommandRegistryService for the given root, with LRU eviction. */
  private getOrCreateRegistry(root: string): CommandRegistryService {
    let registry = this.commandRegistries.get(root);
    if (!registry) {
      if (this.commandRegistries.size >= ClaudeCodeRuntime.MAX_COMMAND_REGISTRIES) {
        const oldest = this.commandRegistries.keys().next().value!;
        this.commandRegistries.delete(oldest);
      }
      registry = new CommandRegistryService(root);
      this.commandRegistries.set(root, registry);
    }
    return registry;
  }
```

Note: The `CommandEntry` type import is already available since it's used by `CommandRegistryService`. Verify that `CommandEntry` is imported from `@dorkos/shared/types`. If not, add the import.

**Merge strategy:**
- SDK commands are the authoritative list (includes built-ins, user-level, skills, project-level)
- Filesystem scanner provides enrichment metadata (`namespace`, `command`, `allowedTools`, `filePath`) for project-level commands
- Matching is by `fullCommand` string (e.g., `/daily:plan`)
- SDK-only commands (e.g., `/compact`) appear without filesystem metadata
- `forceRefresh=true` clears `cachedSdkCommands` to null so the next `sendMessage` re-fetches

**Acceptance criteria:**
1. After first `sendMessage`, `getCommands()` returns SDK commands merged with filesystem metadata
2. Before any `sendMessage`, `getCommands()` returns filesystem-only commands (fallback)
3. SDK commands without filesystem matches appear with only `fullCommand`, `description`, `argumentHint`
4. SDK commands with filesystem matches include `namespace`, `command`, `allowedTools`, `filePath` from filesystem
5. Results are sorted alphabetically by `fullCommand`
6. `forceRefresh=true` clears the SDK cache
7. `getOrCreateRegistry()` maintains the existing LRU eviction behavior (max 50 registries)

Add tests to the existing `apps/server/src/services/runtimes/claude-code/__tests__/claude-code-runtime.test.ts` file to cover SDK command caching, merge logic, fallback behavior, and cache invalidation.

The test file already mocks the SDK, logger, and all dependencies. Follow the existing patterns in the file.

**File:** `apps/server/src/services/runtimes/claude-code/__tests__/claude-code-runtime.test.ts`

Add the following describe blocks inside the existing `describe('ClaudeCodeRuntime', ...)` block, after the existing test cases:

```typescript
  describe('getCommands()', () => {
    describe('filesystem fallback', () => {
      it('returns filesystem-only commands when SDK cache is empty', async () => {
        // Before any sendMessage, getCommands should delegate to CommandRegistryService
        const result = await agentManager.getCommands(false, '/mock');
        // CommandRegistryService will return empty (no .claude/commands/ in mock fs)
        expect(result).toEqual({
          commands: [],
          lastScanned: expect.any(String),
        });
      });
    });

    describe('SDK command caching', () => {
      it('caches SDK commands on first sendMessage callback', async () => {
        const { query: mockedQuery } = await import('@anthropic-ai/claude-agent-sdk');

        // Mock SDK to yield init + result, and make supportedCommands resolve
        const mockSupportedCommands = vi.fn().mockResolvedValue([
          { name: '/compact', description: 'Compact conversation history', argumentHint: '' },
          { name: '/help', description: 'Show help', argumentHint: '[topic]' },
        ]);

        (mockedQuery as ReturnType<typeof vi.fn>).mockReturnValue({
          [Symbol.asyncIterator]: async function* () {
            yield {
              type: 'system', subtype: 'init', session_id: 's1', model: 'test',
              permissionMode: 'default', tools: [], mcp_servers: [], slash_commands: [],
              output_style: 'normal', skills: [], plugins: [], cwd: '/mock',
              apiKeySource: 'env', uuid: 'uuid-1',
            };
            yield {
              type: 'result', subtype: 'success', duration_ms: 100, duration_api_ms: 80,
              is_error: false, num_turns: 1, result: '', stop_reason: 'end_turn',
              total_cost_usd: 0.001, usage: { input_tokens: 10, output_tokens: 5,
                cache_read_input_tokens: 0, cache_creation_input_tokens: 0 },
              modelUsage: {}, permission_denials: [], uuid: 'uuid-2', session_id: 's1',
            };
          },
          supportedModels: vi.fn().mockResolvedValue([]),
          mcpServerStatus: vi.fn().mockResolvedValue([]),
          supportedCommands: mockSupportedCommands,
          abort: vi.fn(),
        });

        agentManager.ensureSession('s1', { permissionMode: 'default' });
        const events = [];
        for await (const event of agentManager.sendMessage('s1', 'hello')) {
          events.push(event);
        }

        // Allow the non-blocking supportedCommands promise to resolve
        await vi.waitFor(async () => {
          expect(mockSupportedCommands).toHaveBeenCalled();
        });

        // Now getCommands should return SDK-sourced commands
        const result = await agentManager.getCommands(false, '/mock');
        expect(result.commands).toEqual(
          expect.arrayContaining([
            expect.objectContaining({ fullCommand: '/compact', description: 'Compact conversation history' }),
            expect.objectContaining({ fullCommand: '/help', description: 'Show help', argumentHint: '[topic]' }),
          ])
        );
      });

      it('does not re-fetch SDK commands on subsequent sendMessage calls', async () => {
        const { query: mockedQuery } = await import('@anthropic-ai/claude-agent-sdk');

        const mockSupportedCommands = vi.fn().mockResolvedValue([
          { name: '/compact', description: 'Compact conversation history', argumentHint: '' },
        ]);

        const makeQueryResult = () => ({
          [Symbol.asyncIterator]: async function* () {
            yield {
              type: 'system', subtype: 'init', session_id: 's1', model: 'test',
              permissionMode: 'default', tools: [], mcp_servers: [], slash_commands: [],
              output_style: 'normal', skills: [], plugins: [], cwd: '/mock',
              apiKeySource: 'env', uuid: 'uuid-1',
            };
            yield {
              type: 'result', subtype: 'success', duration_ms: 100, duration_api_ms: 80,
              is_error: false, num_turns: 1, result: '', stop_reason: 'end_turn',
              total_cost_usd: 0.001, usage: { input_tokens: 10, output_tokens: 5,
                cache_read_input_tokens: 0, cache_creation_input_tokens: 0 },
              modelUsage: {}, permission_denials: [], uuid: 'uuid-2', session_id: 's1',
            };
          },
          supportedModels: vi.fn().mockResolvedValue([]),
          mcpServerStatus: vi.fn().mockResolvedValue([]),
          supportedCommands: mockSupportedCommands,
          abort: vi.fn(),
        });

        (mockedQuery as ReturnType<typeof vi.fn>).mockReturnValue(makeQueryResult());

        agentManager.ensureSession('s1', { permissionMode: 'default' });
        for await (const _ of agentManager.sendMessage('s1', 'hello')) { /* drain */ }
        await vi.waitFor(() => expect(mockSupportedCommands).toHaveBeenCalledTimes(1));

        // Second sendMessage should NOT call supportedCommands again (cache populated)
        (mockedQuery as ReturnType<typeof vi.fn>).mockReturnValue(makeQueryResult());
        for await (const _ of agentManager.sendMessage('s1', 'hello again')) { /* drain */ }

        // supportedCommands should still only have been called once
        expect(mockSupportedCommands).toHaveBeenCalledTimes(1);
      });

      it('clears SDK command cache on forceRefresh', async () => {
        const { query: mockedQuery } = await import('@anthropic-ai/claude-agent-sdk');

        const mockSupportedCommands = vi.fn().mockResolvedValue([
          { name: '/compact', description: 'Compact history', argumentHint: '' },
        ]);

        (mockedQuery as ReturnType<typeof vi.fn>).mockReturnValue({
          [Symbol.asyncIterator]: async function* () {
            yield {
              type: 'system', subtype: 'init', session_id: 's1', model: 'test',
              permissionMode: 'default', tools: [], mcp_servers: [], slash_commands: [],
              output_style: 'normal', skills: [], plugins: [], cwd: '/mock',
              apiKeySource: 'env', uuid: 'uuid-1',
            };
            yield {
              type: 'result', subtype: 'success', duration_ms: 100, duration_api_ms: 80,
              is_error: false, num_turns: 1, result: '', stop_reason: 'end_turn',
              total_cost_usd: 0.001, usage: { input_tokens: 10, output_tokens: 5,
                cache_read_input_tokens: 0, cache_creation_input_tokens: 0 },
              modelUsage: {}, permission_denials: [], uuid: 'uuid-2', session_id: 's1',
            };
          },
          supportedModels: vi.fn().mockResolvedValue([]),
          mcpServerStatus: vi.fn().mockResolvedValue([]),
          supportedCommands: mockSupportedCommands,
          abort: vi.fn(),
        });

        agentManager.ensureSession('s1', { permissionMode: 'default' });
        for await (const _ of agentManager.sendMessage('s1', 'hello')) { /* drain */ }
        await vi.waitFor(() => expect(mockSupportedCommands).toHaveBeenCalled());

        // Verify SDK commands are cached
        const before = await agentManager.getCommands(false, '/mock');
        expect(before.commands.length).toBeGreaterThan(0);

        // forceRefresh should clear the SDK cache
        const after = await agentManager.getCommands(true, '/mock');
        // After clearing, falls back to filesystem (empty in test env)
        expect(after.commands).toEqual([]);
      });
    });

    describe('command source merging', () => {
      it('sorts merged commands alphabetically by fullCommand', async () => {
        const { query: mockedQuery } = await import('@anthropic-ai/claude-agent-sdk');

        const mockSupportedCommands = vi.fn().mockResolvedValue([
          { name: '/zebra', description: 'Z command', argumentHint: '' },
          { name: '/alpha', description: 'A command', argumentHint: '' },
          { name: '/middle', description: 'M command', argumentHint: '' },
        ]);

        (mockedQuery as ReturnType<typeof vi.fn>).mockReturnValue({
          [Symbol.asyncIterator]: async function* () {
            yield {
              type: 'system', subtype: 'init', session_id: 's1', model: 'test',
              permissionMode: 'default', tools: [], mcp_servers: [], slash_commands: [],
              output_style: 'normal', skills: [], plugins: [], cwd: '/mock',
              apiKeySource: 'env', uuid: 'uuid-1',
            };
            yield {
              type: 'result', subtype: 'success', duration_ms: 100, duration_api_ms: 80,
              is_error: false, num_turns: 1, result: '', stop_reason: 'end_turn',
              total_cost_usd: 0.001, usage: { input_tokens: 10, output_tokens: 5,
                cache_read_input_tokens: 0, cache_creation_input_tokens: 0 },
              modelUsage: {}, permission_denials: [], uuid: 'uuid-2', session_id: 's1',
            };
          },
          supportedModels: vi.fn().mockResolvedValue([]),
          mcpServerStatus: vi.fn().mockResolvedValue([]),
          supportedCommands: mockSupportedCommands,
          abort: vi.fn(),
        });

        agentManager.ensureSession('s1', { permissionMode: 'default' });
        for await (const _ of agentManager.sendMessage('s1', 'hello')) { /* drain */ }
        await vi.waitFor(() => expect(mockSupportedCommands).toHaveBeenCalled());

        const result = await agentManager.getCommands(false, '/mock');
        const names = result.commands.map((c) => c.fullCommand);
        expect(names).toEqual(['/alpha', '/middle', '/zebra']);
      });
    });
  });
```

**Key testing patterns used:**
- `vi.waitFor()` to await the non-blocking `supportedCommands()` promise resolution
- Mock the SDK `query()` return value to include `supportedCommands` as a method on the query object
- The existing `beforeEach` calls `vi.resetModules()` and re-imports, giving each test a fresh runtime
- Follow the existing pattern of `for await ... of agentManager.sendMessage()` to drain the stream

**Acceptance criteria:**
1. All new tests pass with `pnpm vitest run apps/server/src/services/runtimes/claude-code/__tests__/claude-code-runtime.test.ts`
2. Tests cover: filesystem fallback, SDK caching on first message, no re-fetch on second message, forceRefresh cache clearing, alphabetical sorting
3. Existing tests in the file continue to pass

Add a schema validation test for SDK-only commands and verify existing route tests pass with optional fields.

**File 1: Schema test** â€” Create or add to an appropriate test file. The simplest approach is to add a small test block to `apps/server/src/routes/__tests__/commands.test.ts` since it already tests the commands API.

Add this test inside the existing `describe('Commands Routes', ...)` block:

```typescript
  describe('schema validation', () => {
    it('accepts commands with optional namespace, command, and filePath', async () => {
      // SDK-only commands (built-ins, skills) have no filesystem metadata
      const registry = {
        commands: [
          {
            fullCommand: '/compact',
            description: 'Compact conversation history',
          },
          {
            fullCommand: '/help',
            description: 'Show help',
            argumentHint: '[topic]',
          },
        ],
        lastScanned: '2024-01-01T00:00:00.000Z',
      };
      mockGetCommands.mockResolvedValue(registry);

      const res = await request(app).get('/api/commands');
      expect(res.status).toBe(200);
      expect(res.body.commands).toHaveLength(2);
      expect(res.body.commands[0]).toEqual({
        fullCommand: '/compact',
        description: 'Compact conversation history',
      });
      expect(res.body.commands[1]).toEqual({
        fullCommand: '/help',
        description: 'Show help',
        argumentHint: '[topic]',
      });
    });

    it('accepts mixed commands with and without filesystem metadata', async () => {
      const registry = {
        commands: [
          {
            fullCommand: '/compact',
            description: 'Compact conversation history',
          },
          {
            namespace: 'daily',
            command: 'plan',
            fullCommand: '/daily:plan',
            description: 'Plan day',
            filePath: '.claude/commands/daily/plan.md',
            allowedTools: ['Read', 'Write'],
          },
        ],
        lastScanned: '2024-01-01T00:00:00.000Z',
      };
      mockGetCommands.mockResolvedValue(registry);

      const res = await request(app).get('/api/commands');
      expect(res.status).toBe(200);
      expect(res.body.commands).toHaveLength(2);
      // SDK-only command
      expect(res.body.commands[0].namespace).toBeUndefined();
      expect(res.body.commands[0].filePath).toBeUndefined();
      // Filesystem-enriched command
      expect(res.body.commands[1].namespace).toBe('daily');
      expect(res.body.commands[1].filePath).toBe('.claude/commands/daily/plan.md');
    });
  });
```

